function solve(points: number[][]): number {
    const MOD = 10**9 + 7;
    const n = points.length;
    const yMap = new Map<number, number[]>();

    // Group points by their y-coordinate
    for (const [x, y] of points) {
        if (!yMap.has(y)) {
            yMap.set(y, []);
        }
        yMap.get(y)!.push(x);
    }

    let result = 0;

    // For each y-coordinate, consider pairs of points on that line
    for (const [y, xs] of yMap.entries()) {
        const m = xs.length;
        // For each pair of points on the same y-coordinate line
        for (let i = 0; i < m; i++) {
            for (let j = i + 1; j < m; j++) {
                const x1 = xs[i];
                const x2 = xs[j];
                // Find how many points are on the same x-coordinate as x1 or x2
                let count = 0;
                for (const [y2, xs2] of yMap.entries()) {
                    if (y2 === y) continue;
                    // Check if there are points with x-coordinate x1 or x2 on this line
                    if (xs2.includes(x1)) count++;
                    if (xs2.includes(x2)) count++;
                }
                // The number of ways to choose 2 points from the count is C(count, 2)
                const c = count * (count - 1) / 2;
                result = (result + c) % MOD;
            }
        }
    }

    return result;
}

